#define MIN(a, b) ((a)<=(b) ? (a) : (b))

kernel void dynproc_kernel(
    int num_steps,
    const int* wall_data,
    const int* src_buf,
    int* dst_buf,
    int cols,
    int rows,
    int row_offset,
    int borderCols,
    int halo,
    local int* local_src1,
    local int* local_src2,
    int* output_buffer
) {
    int n = (int)get_global_id(0);
    if (n >= cols) return;

    for (int s = 0; s < num_steps; s++) {
        int src_val;
        int left_val;
        int right_val;

        if (s == 0) {
            src_val = src_buf[n];
            if (n > 0) left_val = src_buf[n-1];
            if (n < cols - 1) right_val = src_buf[n+1];
        } else {
            src_val = dst_buf[n];
            if (n > 0) left_val = dst_buf[n-1];
            if (n < cols - 1) right_val = dst_buf[n+1];
        }

        int min_val = src_val;
        if (n > 0) {
            min_val = MIN(min_val, left_val);
        }
        if (n < cols - 1) {
            min_val = MIN(min_val, right_val);
        }

        int r = row_offset + s;
        int wall_val = wall_data[r * cols + n];

        dst_buf[n] = wall_val + min_val;
    }
}
